// Cache stampede prevention: use lock/semaphore
func getWithLock(key string) (value, error) {
    if cached, ok := cache.Get(key); ok {
        return cached, nil
    }
    lock.Lock(key)  // Only first goroutine fetches
    defer lock.Unlock(key)
    // Second check after lock
    if cached, ok := cache.Get(key); ok {
        return cached, nil
    }
    value := db.Get(key)
    cache.Set(key, value, 3600)
    return value
}

